const body = $input.first().json.body || {};
const projectId = 'track_' + Date.now();
const provider = body.provider || 'openai';
const metadata = {
  project_id: projectId,
  provider: provider,
  title: body.title || 'Untitled Track',
  genre: body.genre || 'electronic',
  mood: body.mood || 'epic',
  concept: {},
  assets: {},
  timestamps: [],
  uploads: {
    youtube: false,
    tiktok: false,
    instagram: false
  },
  analytics: {},
  created_at: new Date().toISOString()
};
const prompt = `You are a music marketing expert. Create a detailed concept for a ${metadata.genre} track titled "${metadata.title}" with a ${metadata.mood} mood.\n\nReturn ONLY a JSON object with these keys:\nsuno_prompt: a detailed prompt for Suno AI to generate the track\nleonardo_prompt: a prompt for Leonardo AI to generate cover art\nyoutube_title: title for YouTube\nyoutube_description: description for YouTube (include hashtags)\ntiktok_caption: caption for TikTok (include hashtags)\ninstagram_caption: caption for Instagram (include hashtags)\nhook: the main viral hook of the song (1 sentence)\n`;
return {
  json: { projectId, provider, prompt, metadata }
};

const input = $input.first().json;
const model = input.provider === 'openai' ? 'gpt-4o-mini' : input.provider === 'anthropic' ? 'claude-3-5-sonnet-20241022' : input.provider === 'mistral' ? 'mistral-medium-latest' : 'deepseek-chat';
const data = await $httpRequest({
  method: 'POST',
  url: 'https://api.automaton.neurenova.tech/ai/generate',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    provider: input.provider,
    prompt: input.prompt,
    model: model,
    temperature: 0.8,
    max_tokens: 1024
  })
});
return { json: data };

const aiText = $input.first().json.text;
const { projectId, provider, metadata } = $('Create Metadata').item.json;
let concept = {};
try {
  const parsed = JSON.parse(aiText);
  concept = parsed;
} catch (e) {
  // Fallback: store raw text if JSON parsing fails
  concept = { raw: aiText };
}
metadata.concept = concept;
metadata.concept.provider = provider;
return {
  json: { projectId, metadata }
};

const input = $input.first().json;
const projectId = input.projectId;
const metadata = input.metadata;
const data = await $httpRequest({
  method: 'POST',
  url: 'https://api.automaton.neurenova.tech/projects/' + projectId,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(metadata)
});
return { json: { ...data, projectId } };

const input = $input.first().json;
const projectId = input.projectId;
const data = await $httpRequest({
  method: 'POST',
  url: 'https://api.automaton.neurenova.tech/jobs/ffmpeg',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    project_id: projectId,
    task: 'render_long',
    schema: 'music_ai',
    cover_path: 'assets/cover.png',
    audio_path: 'assets/audio.mp3',
    output_path: 'outputs/video_long.mp4'
  })
});
return { json: { ...data, projectId } };
